// Fetch cloud cover and pressure for a 5×5 grid around center lat/lon.
// Returns Result: { ok: true, data: { grid: [...] } } or { ok: false, error }.
// Uses Open-Meteo multi-location API — one request for all 25 points.
async function fetchWeatherGrid(centerLat: number, centerLon: number) {
  try {
    const GRID_SIZE = 5;
    const SPACING = 0.5; // degrees (~55km at mid-latitudes)
    const HALF = Math.floor(GRID_SIZE / 2);

    // Build grid of lat/lon coordinates centered on the given position
    const lats: number[] = [];
    const lons: number[] = [];
    for (let row = -HALF; row <= HALF; row++) {
      for (let col = -HALF; col <= HALF; col++) {
        // Clamp to valid ranges
        const lat = Math.max(-90, Math.min(90, centerLat + row * SPACING));
        const lon = Math.max(-180, Math.min(180, centerLon + col * SPACING));
        lats.push(Math.round(lat * 1000) / 1000);
        lons.push(Math.round(lon * 1000) / 1000);
      }
    }

    // Open-Meteo multi-location: comma-separated lat/lon values
    const latStr = lats.join(',');
    const lonStr = lons.join(',');
    const forecastHours = config.get('DEFAULT_FORECAST_HOURS') || 48;

    // Only request cloud_cover and pressure_msl — keep it fast
    const params = 'cloud_cover,pressure_msl';
    const url = `https://api.open-meteo.com/v1/forecast`
      + `?latitude=${latStr}&longitude=${lonStr}`
      + `&current=${params}`
      + `&hourly=${params}`
      + `&forecast_hours=${forecastHours}`
      + `&timezone=auto`;

    const res = await fetch(url);
    if (!res.ok) {
      return {
        ok: false,
        error: { code: 'GRID_API_ERROR', message: `Open-Meteo grid API error: ${res.status}` }
      };
    }

    const rawData = await res.json();

    // Multi-location response is an array of forecast objects (one per point)
    // Single-location returns a plain object — normalize to array
    const forecasts = Array.isArray(rawData) ? rawData : [rawData];

    // Map each forecast to a compact grid point with current + hourly data
    const grid = forecasts.map((fc: any, i: number) => ({
      lat: lats[i],
      lon: lons[i],
      // Current values
      cloudCover: fc.current?.cloud_cover ?? 0,
      pressure: fc.current?.pressure_msl ?? 1013,
      // Hourly arrays for timeline scrubbing
      hourly: fc.hourly?.time?.map((time: string, h: number) => ({
        time,
        cloudCover: fc.hourly.cloud_cover?.[h] ?? 0,
        pressure: fc.hourly.pressure_msl?.[h] ?? 1013
      })) ?? []
    }));

    return { ok: true, data: { grid, centerLat, centerLon } };
  } catch (err) {
    return {
      ok: false,
      error: { code: 'GRID_API_ERROR', message: (err as Error).message || 'Unexpected error fetching grid weather' }
    };
  }
}
